    n= len(letters)
    start=0
    end=len(letters)-1
    ans=0
    while start<=end:
        mid=(start+end)//2
        if letters[mid]==target:
            ans.append(letters[mid])
        elif letters[mid]<target:
            end=mid-1
        else:
            start=mid+1
    if ans!=0:
        return ans
    else:
        return letters[0]

