def InnerSum(root):
    ans = []
    s = 0
    def rec(node):
        if node is None:
            return 0

        if (node.left != None or node.right != None):
            ans.append(node.val)
        rec(node.left)
        rec(node.right)

    rec(root)
    for i in ans:
        s += i
    final = s - root.val
    return final

